import React, { useState, useEffect } from 'react';

const FirefighterCharacter = ({ size=180, speaking=false, waving=false, style={}, expression='happy' }) => {
  const [blinking, setBlinking] = useState(false);
  const [mouthOpen, setMouthOpen] = useState(false);

  useEffect(() => {
    const id = setInterval(() => { setBlinking(true); setTimeout(()=>setBlinking(false),150); }, 3000+Math.random()*2000);
    return () => clearInterval(id);
  }, []);

  useEffect(() => {
    if (!speaking) { setMouthOpen(false); return; }
    const id = setInterval(() => setMouthOpen(p=>!p), 300);
    return () => clearInterval(id);
  }, [speaking]);

  const w = size; const h = size*1.4;
  return (
    <div className={waving?'char-waving':'char-bob'} style={{ width:w, height:h, position:'relative', flexShrink:0, ...style }}>
      <svg width={w} height={h} viewBox="0 0 200 280" fill="none" xmlns="http://www.w3.org/2000/svg" overflow="visible">
        <rect x="62" y="118" width="76" height="82" rx="12" fill="#1a1a1a"/>
        <rect x="62" y="128" width="76" height="10" rx="2" fill="#F5C518"/>
        <rect x="62" y="148" width="76" height="10" rx="2" fill="#F5C518"/>
        <rect x="62" y="168" width="76" height="10" rx="2" fill="#F5C518"/>
        <line x1="100" y1="118" x2="100" y2="200" stroke="#333" strokeWidth="1.5"/>
        <rect x="36" y="122" width="28" height="54" rx="13" fill="#1a1a1a"/>
        <rect x="36" y="150" width="28" height="8" rx="2" fill="#F5C518"/>
        <ellipse cx="50" cy="180" rx="13" ry="11" fill="#E8A0B0"/>
        <g className={waving?'arm-wave':''} style={{transformOrigin:'150px 130px'}}>
          <rect x="136" y="122" width="28" height="54" rx="13" fill="#1a1a1a"/>
          <rect x="136" y="150" width="28" height="8" rx="2" fill="#F5C518"/>
          <ellipse cx="150" cy="180" rx="13" ry="11" fill="#E8A0B0"/>
        </g>
        <rect x="68" y="197" width="28" height="48" rx="8" fill="#1a1a1a"/>
        <rect x="63" y="236" width="38" height="18" rx="8" fill="#1a1a1a"/>
        <rect x="63" y="246" width="38" height="7" rx="3" fill="#F5C518"/>
        <rect x="104" y="197" width="28" height="48" rx="8" fill="#1a1a1a"/>
        <rect x="99" y="236" width="38" height="18" rx="8" fill="#1a1a1a"/>
        <rect x="99" y="246" width="38" height="7" rx="3" fill="#F5C518"/>
        <rect x="88" y="108" width="24" height="18" rx="6" fill="#E8A0B0"/>
        <path d="M62 65 Q62 22 100 20 Q138 22 138 65 Q140 92 128 107 Q114 120 100 120 Q86 120 72 107 Q60 92 62 65Z" fill="#E8A0B0"/>
        <ellipse cx="74" cy="86" rx="9" ry="6" fill="#F0B0C0" opacity="0.65"/>
        <ellipse cx="126" cy="86" rx="9" ry="6" fill="#F0B0C0" opacity="0.65"/>
        <path d="M70 54 Q67 44 74 40 Q82 36 90 40" fill="#4CAF50"/>
        <path d="M130 54 Q133 44 126 40 Q118 36 110 40" fill="#4CAF50"/>
        <ellipse cx="100" cy="52" rx="50" ry="10" fill="#CC2200"/>
        <path d="M54 52 Q52 20 100 17 Q148 20 146 52Z" fill="#DD2200"/>
        <path d="M66 36 Q82 23 100 21 Q90 30 78 40Z" fill="#FF4422" opacity="0.35"/>
        <path d="M93 31 L100 25 L107 31 L105 41 L100 44 L95 41Z" fill="#F5C518"/>
        <path d="M95 33 L100 28 L105 33 L103 40 L100 42 L97 40Z" fill="#E8A000"/>
        <ellipse cx="82" cy="73" rx="11" ry="11" fill="white"/>
        <ellipse cx="118" cy="73" rx="11" ry="11" fill="white"/>
        <ellipse cx="82" cy="74" rx="7.5" ry={blinking?1:7.5} fill="#1a1a1a"/>
        <ellipse cx="118" cy="74" rx="7.5" ry={blinking?1:7.5} fill="#1a1a1a"/>
        {!blinking && <><circle cx="85" cy="71" r="2.2" fill="white"/><circle cx="121" cy="71" r="2.2" fill="white"/></>}
        {expression==='happy' && <path d={mouthOpen?'M88 97 Q100 110 112 97':'M88 97 Q100 105 112 97'} stroke="#1a1a1a" strokeWidth="3" strokeLinecap="round" fill={mouthOpen?'#FF8888':'none'}/>}
        {expression==='excited' && <path d="M85 95 Q100 112 115 95" stroke="#1a1a1a" strokeWidth="3" strokeLinecap="round" fill="#FF8888"/>}
        {expression==='surprised' && <ellipse cx="100" cy="101" rx="8" ry="10" fill="#FF8888" stroke="#1a1a1a" strokeWidth="2"/>}
        {speaking && <>
          <circle cx="152" cy="32" r="4" fill="#F5C518" className="speak-dot-1"/>
          <circle cx="162" cy="24" r="3" fill="#F5C518" className="speak-dot-2"/>
          <circle cx="170" cy="17" r="2" fill="#F5C518" className="speak-dot-3"/>
        </>}
      </svg>
    </div>
  );
};
export default FirefighterCharacter;
