import React from 'react';

const Cloud = ({ width }) => (
  <div style={{ position:'relative', width, height:width*0.45 }}>
    <div style={{ position:'absolute', bottom:0, left:'10%', width:'80%', height:'60%', background:'white', borderRadius:999, opacity:0.92 }}/>
    <div style={{ position:'absolute', bottom:'30%', left:'20%', width:'45%', height:'70%', background:'white', borderRadius:999, opacity:0.92 }}/>
    <div style={{ position:'absolute', bottom:'20%', left:'50%', width:'38%', height:'55%', background:'white', borderRadius:999, opacity:0.92 }}/>
  </div>
);

const treeColors = { dark:['#2d6e1a','#1a4a0a'], mid:['#4a9e2a','#2d7a10'], light:['#6abf3a','#4a9e20'], teal:['#3a9e8a','#1a7a6a'] };

const BackTree = ({ x, y, size, shade='mid', delay=0 }) => {
  const [top, bottom] = treeColors[shade]||treeColors.mid;
  return (
    <div style={{ position:'absolute', left:x, top:y, transform:'translateX(-50%)', display:'flex', flexDirection:'column', alignItems:'center', animation:`sway ${3.5+delay}s ease-in-out infinite`, animationDelay:`${delay}s`, transformOrigin:'bottom center' }}>
      <div style={{ width:size, height:size*1.3, background:`linear-gradient(180deg,${top} 0%,${bottom} 100%)`, borderRadius:'50% 50% 40% 40%' }}/>
      <div style={{ width:size*0.18, height:size*0.5, background:'#7a5230', borderRadius:4, marginTop:-4 }}/>
    </div>
  );
};

const MidTree = ({ x, y, size, delay=0 }) => (
  <div style={{ position:'absolute', left:x, top:y, transform:'translateX(-50%)', display:'flex', flexDirection:'column', alignItems:'center', animation:`sway ${4+delay}s ease-in-out infinite`, animationDelay:`${delay}s`, transformOrigin:'bottom center' }}>
    <div style={{ width:size*1.1, height:size*1.2, background:'linear-gradient(180deg,#6abf3a 0%,#3d8a10 100%)', borderRadius:'50% 50% 40% 40%', boxShadow:'4px 6px 12px rgba(0,0,0,0.2)' }}/>
    <div style={{ width:size*0.16, height:size*0.55, background:'#8B5E3C', borderRadius:4, marginTop:-6 }}/>
  </div>
);

const ForeTree = ({ x, y, size, delay=0 }) => (
  <div style={{ position:'absolute', left:x, top:y, transform:'translateX(-50%)', display:'flex', flexDirection:'column', alignItems:'center', animation:`sway ${3.5+delay}s ease-in-out infinite`, animationDelay:`${delay}s`, transformOrigin:'bottom center', zIndex:2 }}>
    <div style={{ width:size*1.3, height:size*0.8, background:'linear-gradient(180deg,#5aae3a 0%,#2d7a10 100%)', borderRadius:'50% 50% 40% 40%', boxShadow:'4px 8px 16px rgba(0,0,0,0.25)', marginBottom:-size*0.15 }}/>
    <div style={{ width:size*1.0, height:size*0.7, background:'linear-gradient(180deg,#6abf3a 0%,#3d8a10 100%)', borderRadius:'50% 50% 40% 40%', marginBottom:-size*0.12 }}/>
    <div style={{ width:size*0.75, height:size*0.6, background:'linear-gradient(180deg,#7acf4a 0%,#4a9e20 100%)', borderRadius:'50% 50% 40% 40%' }}/>
    <div style={{ width:size*0.18, height:size*0.7, background:'#6B4226', borderRadius:6, marginTop:-8 }}/>
  </div>
);

const ForestBackground = ({ style={}, showPath=true, timeOfDay='day', showSmoke=false, showFire=false }) => {
  const skyGradient = timeOfDay==='sunset'
    ? 'linear-gradient(180deg,#FF8C42 0%,#FFB347 40%,#87CEEB 100%)'
    : timeOfDay==='dusk'
    ? 'linear-gradient(180deg,#1a1a3e 0%,#2C3E6B 50%,#5B4A8A 100%)'
    : 'linear-gradient(180deg,#87CEEB 0%,#B8E4F7 60%,#D4F0FF 100%)';

  return (
    <div style={{ position:'absolute', inset:0, overflow:'hidden', ...style }}>
      <div style={{ position:'absolute', inset:0, background:skyGradient }}/>
      {timeOfDay==='day' && <div style={{ position:'absolute', top:'5%', right:'8%', width:80, height:80, borderRadius:'50%', background:'radial-gradient(circle,#FFE566 40%,#FFD700 70%,rgba(255,220,50,0) 100%)', boxShadow:'0 0 40px 20px rgba(255,230,80,0.35)', animation:'sunRays 5s ease-in-out infinite' }}/>}
      <div style={{ position:'absolute', top:'6%', left:'6%', animation:'cloudDrift 8s ease-in-out infinite alternate' }}><Cloud width={140}/></div>
      <div style={{ position:'absolute', top:'4%', left:'48%', animation:'cloudDrift 12s ease-in-out infinite alternate-reverse' }}><Cloud width={110}/></div>
      <div style={{ position:'absolute', top:'7%', right:'10%', animation:'cloudDrift 10s ease-in-out infinite alternate' }}><Cloud width={160}/></div>
      <div style={{ position:'absolute', bottom:'30%', left:'-5%', width:'45%', height:'22%', background:'#4a9e2a', borderRadius:'50%', opacity:0.55 }}/>
      <div style={{ position:'absolute', bottom:'28%', right:'-5%', width:'50%', height:'24%', background:'#3a8e1a', borderRadius:'50%', opacity:0.55 }}/>
      <div style={{ position:'absolute', bottom:'26%', left:'25%', width:'55%', height:'20%', background:'#5aae3a', borderRadius:'50%', opacity:0.45 }}/>
      <div style={{ position:'absolute', bottom:0, left:0, right:0, height:'38%', background:'linear-gradient(180deg,#5a9e2f 0%,#3d7a1a 100%)' }}/>
      {showPath && (
        <div style={{ position:'absolute', inset:0, pointerEvents:'none' }}>
          <svg width="100%" height="100%" viewBox="0 0 1200 750" preserveAspectRatio="xMidYMid slice">
            <defs><linearGradient id="pathG" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor="#C4956A"/><stop offset="100%" stopColor="#A67C52"/></linearGradient></defs>
            <path d="M380 750 Q430 640 470 570 Q510 500 545 475 Q580 455 600 452 Q620 455 655 475 Q690 500 720 540 Q750 580 790 750Z" fill="url(#pathG)"/>
            <path d="M455 750 Q490 650 515 585 Q540 520 562 488 Q580 468 600 462 Q620 468 638 488 Q660 520 678 570 Q700 630 730 750Z" fill="#D4A574" opacity="0.45"/>
          </svg>
        </div>
      )}
      <BackTree x="7%" y="28%" size={52} shade="dark" delay={0}/>
      <BackTree x="16%" y="26%" size={60} shade="teal" delay={0.4}/>
      <BackTree x="25%" y="30%" size={48} shade="dark" delay={0.8}/>
      <BackTree x="72%" y="27%" size={55} shade="mid" delay={0.2}/>
      <BackTree x="82%" y="29%" size={50} shade="dark" delay={0.6}/>
      <BackTree x="91%" y="26%" size={58} shade="teal" delay={1.0}/>
      <MidTree x="20%" y="35%" size={80} delay={0}/>
      <MidTree x="32%" y="33%" size={90} delay={0.5}/>
      <MidTree x="68%" y="34%" size={85} delay={0.3}/>
      <MidTree x="80%" y="32%" size={92} delay={0.7}/>
      <ForeTree x="2%" y="22%" size={120} delay={0}/>
      <ForeTree x="92%" y="20%" size={130} delay={0.4}/>
      {[14,22,30,68,76,84].map((x,i)=>(
        <div key={i} style={{ position:'absolute', left:`${x}%`, top:'63%', width:60, height:36, background:i%2===0?'#4a9e2a':'#5aae3a', borderRadius:'50%', transform:'translate(-50%,-50%)' }}/>
      ))}
      {[12,20,28,38,62,72,80,88].map((x,i)=>(
        <div key={i} style={{ position:'absolute', left:`${x}%`, top:'63%', fontSize:18, animation:`grassSway ${2+i*0.25}s ease-in-out infinite`, transformOrigin:'bottom center' }}>🌿</div>
      ))}
      {[10,18,26,70,78,86].map((x,i)=>(
        <div key={i} style={{ position:'absolute', left:`${x}%`, top:'64%', fontSize:14 }}>🌺</div>
      ))}
      {showSmoke && [0,1,2].map(i=>(
        <div key={i} style={{ position:'absolute', left:`${48+i*4}%`, top:'45%', fontSize:28+i*8, animation:`smokeDrift ${1.8+i*0.4}s ease-in-out infinite`, animationDelay:`${i*0.3}s`, opacity:0.6 }}>💨</div>
      ))}
      {showFire && [46,50,54,58,62].map((x,i)=>(
        <div key={i} style={{ position:'absolute', left:`${x}%`, top:'60%', fontSize:28+i*3, animation:`fireFlicker ${0.25+i*0.05}s ease-in-out infinite` }}>🔥</div>
      ))}
      <div style={{ position:'absolute', bottom:0, left:0, right:0, height:'12%', background:'linear-gradient(180deg,#4a9e2a 0%,#3d7a1a 100%)', borderRadius:'60% 60% 0 0 / 30% 30% 0 0' }}/>
      <div style={{ position:'absolute', inset:0, background:'radial-gradient(ellipse at center,transparent 55%,rgba(0,0,0,0.22) 100%)', pointerEvents:'none' }}/>
    </div>
  );
};
export default ForestBackground;
